# Let's convert this grid into a number grid so that addition is easier
# "." --> 0
# "S" --> 1
# '^' --> -1
def parse(input: str) -> list[list[int]]:
    lines = input.split("\n")
    str_grid = [list(line) for line in lines]
    num_grid = [[0] * len(str_grid[0]) for _ in range(len(str_grid))]

    for r in range(len(str_grid)):
        for c in range(len(str_grid[0])):
            if str_grid[r][c] == 'S':
                num_grid[r][c] = 1
            elif str_grid[r][c] == '^':
                num_grid[r][c] = -1
    return num_grid

# Fill in the map first
#   Iterate from top to bottom, left to right
#   empty space is converted if:
#       one above is a beam
#       OR has a splitter to the left or right, with a beam above it
def solve(grid: list[list[int]]) -> int:
    split_beams(grid)
    return num_timelines(grid)

def split_beams(grid: list[list[int]]) -> None:
    # Then split beams
    for r in range(1, len(grid)):
        for c in range(len(grid[0])):
            if grid[r][c] == 0:
                if (grid[r-1][c] >= 1):
                    grid[r][c] += grid[r-1][c]
                if c > 0 and grid[r][c-1] == -1 and grid[r-1][c-1] >= 1:
                    grid[r][c] += grid[r-1][c-1]
                if c < len(grid[0]) - 1 and grid[r][c+1] == -1 and grid[r-1][c+1] >= 1:
                    grid[r][c] += grid[r-1][c+1]

def num_timelines(grid: list[list[int]]) -> int:
    total = 0
    for c in range(len(grid[0])):
        if grid[-1][c] >= 1:
            total += grid[-1][c]
    return total


### Main ###
print(solve(parse(INPUT)))